import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as r,c as t,e as i}from"./chunks/vendor-mermaid.BXjKBAcr.js";const m=JSON.parse(`{"title":"","description":"Join Artha Advisory—Nepal's leading CA firm. Discover career opportunities and join a team of financial leaders.","frontmatter":{"layout":"home","description":"Join Artha Advisory—Nepal's leading CA firm. Discover career opportunities and join a team of financial leaders.","hero":{"name":"Careers at Artha","text":"Build Your Legacy","tagline":"Join Nepal's leading CA firm. A rigorous training ground for future financial leaders.","actions":[{"theme":"brand","text":"View Openings","link":"/careers/openings"},{"theme":"alt","text":"Alumni Network","link":"/about/alumni"}]},"features":[{"title":"Artha Academy","details":"Weekly \\"Learning Fridays\\" on NFRS, Audit, and Soft Skills.","icon":"🎓"},{"title":"Fast Track","details":"Transparent path from Intern to Partner.","icon":"🚀"},{"title":"Mentorship","details":"Direct guidance from partners and seniors.","icon":"🤝"}],"head":[["meta",{"property":"og:image","content":"https://arthaadvisory.com.np/og_image_test.jpg"}],["meta",{"property":"og:title","content":"Artha Advisory"}],["meta",{"property":"og:description","content":"Join Artha Advisory—Nepal's leading CA firm. Discover career opportunities and join a team of financial leaders."}],["meta",{"name":"description","content":"Join Artha Advisory—Nepal's leading CA firm. Discover career opportunities and join a team of financial leaders."}]]},"headers":[],"relativePath":"careers/index.md","filePath":"careers/index.md"}`),n={name:"careers/index.md"};function o(s,a,d,c,l,h){return r(),t("div",null,[...a[0]||(a[0]=[i('<div class="home-content-container"><div class="container mx-auto px-4 py-8"><p>Artha Advisory isn&#39;t just a workplace; it&#39;s a rigorous training ground. Whether you are an aspiring Chartered Accountant (CA) or a seasoned tax professional, we offer a culture of <strong>continuous learning</strong> and <strong>high-impact work</strong>.</p><hr><h2 id="🚀-why-join-artha" tabindex="-1">🚀 Why Join Artha? <a class="header-anchor" href="#🚀-why-join-artha" aria-label="Permalink to &quot;🚀 Why Join Artha?&quot;">​</a></h2><h3 id="_1-the-artha-academy-training-development" tabindex="-1">1. The &quot;Artha Academy&quot; (Training &amp; Development) <a class="header-anchor" href="#_1-the-artha-academy-training-development" aria-label="Permalink to &quot;1. The &quot;Artha Academy&quot; (Training &amp; Development)&quot;">​</a></h3><p>We invest heavily in your growth. Every Friday is &quot;Learning Friday,&quot; where we conduct:</p><ul><li><strong>NFRS Deep Dives</strong>: Practical case studies on complex accounting standards.</li><li><strong>Soft Skills</strong>: Presentation, negotiation, and leadership workshops.</li><li><strong>Tech Training</strong>: Excel mastery, Tally Prime, and Audit software certification.</li></ul><h3 id="_2-structured-training-programs" tabindex="-1">2. Structured Training Programs <a class="header-anchor" href="#_2-structured-training-programs" aria-label="Permalink to &quot;2. Structured Training Programs&quot;">​</a></h3><p>We offer specialized training tracks tailored to your academic path:</p><div class="grid-2"><div class="card"><h3>📘 CA Students (ICAN/ICAI)</h3><p>Structured articleship program compliant with ICAN norms, focusing on Statutory Audit and Tax.</p></div><div class="card"><h3>🌍 ACCA Students</h3><p>Practical experience requirement (PER) support with exposure to IFRS/NFRS and global audit practices.</p></div><div class="card"><h3>🎓 MBA / MBS Graduates</h3><p>Management trainee programs focusing on Financial Analysis, Corporate Advisory, and System Audits.</p></div><div class="card"><h3>📚 BBS / BBA Students</h3><p>Internship opportunities to build a strong foundation in accounting, tax compliance, and corporate culture.</p></div></div><div class="immediate-openings-highlight"><div class="highlight-inner"><div class="highlight-text"><h2>📢 Immediate Openings</h2><p>We are actively hiring for the upcoming audit season. Join a team where your expertise is valued from day one.</p></div><div class="highlight-action"><a href="/careers/openings" class="cta-button">Browse All Openings &amp; Apply</a></div></div></div><hr><h2 id="🚀-why-join-artha-1" tabindex="-1">🚀 Why Join Artha? <a class="header-anchor" href="#🚀-why-join-artha-1" aria-label="Permalink to &quot;🚀 Why Join Artha?&quot;">​</a></h2><p>Artha Advisory isn&#39;t just a workplace; it&#39;s a rigorous training ground. Whether you are an aspiring Chartered Accountant (CA) or a seasoned tax professional, we offer a culture of <strong>continuous learning</strong> and <strong>high-impact work</strong>.</p><h3 id="_1-the-artha-academy-training-development-1" tabindex="-1">1. The &quot;Artha Academy&quot; (Training &amp; Development) <a class="header-anchor" href="#_1-the-artha-academy-training-development-1" aria-label="Permalink to &quot;1. The &quot;Artha Academy&quot; (Training &amp; Development)&quot;">​</a></h3><p>We invest heavily in your growth. Every Friday is &quot;Learning Friday,&quot; where we conduct:</p><ul><li><strong>NFRS Deep Dives</strong>: Practical case studies on complex accounting standards.</li><li><strong>Soft Skills</strong>: Presentation, negotiation, and leadership workshops.</li><li><strong>Tech Training</strong>: Excel mastery, Tally Prime, and Audit software certification.</li></ul><h3 id="_2-structured-training-programs-1" tabindex="-1">2. Structured Training Programs <a class="header-anchor" href="#_2-structured-training-programs-1" aria-label="Permalink to &quot;2. Structured Training Programs&quot;">​</a></h3><p>We offer specialized training tracks tailored to your academic path:</p><div class="grid-2"><div class="card"><h3>📘 CA Students (ICAN/ICAI)</h3><p>Structured articleship program compliant with ICAN norms, focusing on Statutory Audit and Tax.</p></div><div class="card"><h3>🌍 ACCA Students</h3><p>Practical experience requirement (PER) support with exposure to IFRS/NFRS and global audit practices.</p></div><div class="card"><h3>🎓 MBA / MBS Graduates</h3><p>Management trainee programs focusing on Financial Analysis, Corporate Advisory, and System Audits.</p></div><div class="card"><h3>📚 BBS / BBA Students</h3><p>Internship opportunities to build a strong foundation in accounting, tax compliance, and corporate culture.</p></div></div><h3 id="_3-clear-career-path" tabindex="-1">3. Clear Career Path <a class="header-anchor" href="#_3-clear-career-path" aria-label="Permalink to &quot;3. Clear Career Path&quot;">​</a></h3><p>From &quot;Associate&quot; to &quot;Partner,&quot; your growth trajectory is transparent. We have a policy of promoting from within—50% of our current managers started as interns.</p><hr><h2 id="🤝-artha-alumni-network" tabindex="-1">🤝 Artha Alumni Network <a class="header-anchor" href="#🤝-artha-alumni-network" aria-label="Permalink to &quot;🤝 Artha Alumni Network&quot;">​</a></h2><p><em>Once an Artha member, always a member.</em></p><p>Our alumni have gone on to become CFOs of leading banks, multinational corporations, and successful entrepreneurs.</p><p><a href="/about/alumni" class="action-btn">View Our Alumni Network →</a></p></div></div>',1)])])}const g=e(n,[["render",o]]);export{m as __pageData,g as default};
